import React from 'react';
import { useNavigate } from 'react-router-dom';
import CaseCard from '../components/CaseCard';

// Временные мок-данные (позже заменим на запрос к API)
const mockCases = [
  { 
    id: 1, 
    name: 'Базовый кейс', 
    price_stars: 50, 
    image_url: 'https://via.placeholder.com/150/ffd700/000000?text=Case' 
  },
  { 
    id: 2, 
    name: 'Премиум кейс', 
    price_stars: 200, 
    image_url: 'https://via.placeholder.com/150/ffa500/000000?text=Premium' 
  },
  { 
    id: 3, 
    name: 'Легендарный кейс', 
    price_stars: 500, 
    image_url: 'https://via.placeholder.com/150/ff4500/000000?text=Legend' 
  },
];

const Home: React.FC = () => {
  const navigate = useNavigate();

  return (
    <>
      <h1>🎲 FazerCases</h1>
      <div className="cases-grid">
        {mockCases.map(caseItem => (
          <CaseCard
            key={caseItem.id}
            caseData={caseItem}
            onOpen={() => navigate(`/case/${caseItem.id}`)}
          />
        ))}
      </div>
    </>
  );
};

export default Home;
